-- Berikad kontext för G 110 Tjängvidestenen (segel/skepp, Oden på Sleipner, valkyria,
-- datering 700–900-tal, Historiska museet). Applicerad på prod 2026-07-22.
UPDATE runic_inscriptions SET historical_context =
'Run- och bildsten från Alskogs socken, Gotland (funnen inmurad i en källare 1844), daterad till 700–900-tal; förvaras på Historiska museet, vars logotyp bygger på en av stenens bilder. Övre bildfältet visar en åttafotad häst (troligen Sleipner) med ryttare — Oden, eller en död krigare på väg till Valhall — som tas emot av en kvinna med välkomsthorn (tolkad som valkyria). Det nedre fältet domineras av ett långskepp med ett ovanligt stort, brett segel — en av de tydligaste segelframställningarna i det vikingatida bildmaterialet. Tolkningarna är osäkra och runinskriften fragmentarisk (kortkvistrunor): "… reste stenen efter Hjorulf, sin broder …". Hedniskt ursprung antas då inga kristna tecken finns.'
WHERE signum='G 110';
